mapper.select:
SELECT COUNT(*) FROM MEMBER m
AND ( m.MEMBER_ID LIKE '%' || #{keyword} || '%' OR m.NICKNAME LIKE '%' || #{keyword} || '%' OR m.EMAIL LIKE '%' || #{keyword} || '%' )
AND m.ROLE = #{role}
AND m.STATUS = #{status}
AND m.CREATED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND m.CREATED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1 - 1/86400

WITH LatestReports AS ( SELECT TARGET_MEMBER_ID, REASON, RESULT_STATUS, CREATED_AT, ROW_NUMBER() OVER (PARTITION BY TARGET_MEMBER_ID ORDER BY CREATED_AT DESC) as rn FROM MEMBER_REPORT_HISTORY ), ReportStats AS ( SELECT TARGET_MEMBER_ID, COUNT(*) AS REPORT_COUNT, MAX(CREATED_AT) AS LATEST_REPORT_DATE FROM MEMBER_REPORT_HISTORY GROUP BY TARGET_MEMBER_ID ), PagedMembers AS ( SELECT m.MEMBER_ID, m.NICKNAME, m.EMAIL, m.ROLE, m.STATUS, m.SOCIAL_PROVIDER AS provider, TO_CHAR(m.CREATED_AT, 'YYYY.MM.DD HH24:MI') AS joined_at, TO_CHAR(m.LAST_LOGIN, 'YYYY.MM.DD HH24:MI') AS last_login, NVL(s.REPORT_COUNT, 0) AS reports, r.REASON AS report_reason, TO_CHAR(s.LATEST_REPORT_DATE, 'YYYY.MM.DD') AS last_report_date, NVL(r.RESULT_STATUS, '없음') AS result_status, TO_CHAR(m.SUSPENSION_END_DATE, 'YYYY.MM.DD') AS suspension_end_date, ROW_NUMBER() OVER (
ORDER BY NVL(s.REPORT_COUNT, 0) DESC, m.CREATED_AT DESC
ORDER BY m.LAST_LOGIN DESC NULLS LAST, m.CREATED_AT DESC
ORDER BY m.CREATED_AT ASC
ORDER BY m.CREATED_AT DESC
) AS rnum FROM MEMBER m LEFT JOIN ReportStats s ON m.MEMBER_ID = s.TARGET_MEMBER_ID LEFT JOIN LatestReports r ON m.MEMBER_ID = r.TARGET_MEMBER_ID AND r.rn = 1
AND ( m.MEMBER_ID LIKE '%' || #{keyword} || '%' OR m.NICKNAME LIKE '%' || #{keyword} || '%' OR m.EMAIL LIKE '%' || #{keyword} || '%' )
AND m.ROLE = #{role}
AND m.STATUS = #{status}
AND m.CREATED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND m.CREATED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1 - 1/86400
) SELECT * FROM PagedMembers WHERE rnum > #{offset} AND rnum <= #{offset} + #{size}
